var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>별들의 유해가 잠든 심연으로 가라앉는다.</color>","JPN":"<color=#ff3636>星の遺体が眠る深淵に沈んでゆく。</color>","ENG":"<color=#ff3636>The remnants of the stars sink into the sleeping abyss.</color>","TWN":"<color=#ff3636>星星遺骸沉入沉睡的深淵。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>심연 너머에서 불경한 아우성이 들려온다.</color>","JPN":"<color=#ff3636>深淵の向こうから不敬なわめき声が聞こえてくる。</color>","ENG":"<color=#ff3636>Beyond the abyss, I hear the sacrilegious cry.</color>","TWN":"<color=#ff3636>深淵那頭傳來不敬的低語聲。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>너는 선택받았다.</color>","JPN":"<color=#ff3636>お前は選ばれた。</color>","ENG":"<color=#ff3636>You have been chosen.</color>","TWN":"<color=#ff3636>你是被選中之人。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사실대로 말해요. 제프티 이야기가 전부 사실인가요?","JPN":"本当のことを話しなさい。ジェフティの話はすべて事実ですか？","ENG":"Tell me the truth. Is the Jehuty story true?","TWN":"你老實說，傑夫堤的事全都是真的嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도시 한복판에서 인체 실험을 벌였다는 게 사실이냐고요.","JPN":"都市の真ん中で人体実験を行ったということが事実なのかと、聞いています。","ENG":"Did they, or did they not conduct human experiments in the middle of the city?","TWN":"我問你在城市中心進行了人體實驗的事是不是真的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"진정하세요. 차근차근 설명해 드릴게요.","JPN":"落ち着いてください。わかるように説明します。","ENG":"Please, calm down. We'll explain everything.","TWN":"你冷靜點，我們慢慢和你解釋。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설명? 이제는 저를 아예 바보 취급하려는 건가요?","JPN":"説明？　私をバカにしているのですか？","ENG":"Explain? Do you think I am some fool?!","TWN":"解釋？現在你是想拿我當傻子嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"긴말 안 하겠습니다. 내일부터 한동안 요양을 다녀올 거예요.","JPN":"単刀直入に言います。明日からしばらく療養に出ます。","ENG":"I will make this short. Starting tomorrow, I will take leave for a while.","TWN":"我就不多說了，從明天起，我會去休養一段時間。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"요양이라니요? 이런 중요한 시기에?","JPN":"療養ですか？　このような大事な時期に？","ENG":"Leave? At an important time like this?","TWN":"休養？在這麼重要的時候？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 요즘 들어 다시 몸 상태가 나빠졌으니까요.","JPN":"はい。最近また身体の具合が悪くなりましたから。","ENG":"Yes. My condition seems to have worsened the past few days.","TWN":"是的，因為最近我的身體狀況又變差了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"일시적인 현상이랍니다. 곧 나아지실 거예요.","JPN":"一時的な現象ですよ。すぐ良くなります。","ENG":"We're sure it's just passing. You'll recover soon.","TWN":"這些都只是暫時的。你很快就會好起來的。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일시적이라고요?","JPN":"一時的ですって？","ENG":"Passing?","TWN":"暫時的？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"불을 끄고 침대에 누우면 벽 속에서 들려서는 안 될 소리가 들려와요.","JPN":"電気を消してベッドに横になると、壁の中から聞こえてはいけない音が聞こえてきますわ。","ENG":"When I turn off the lights and lie in my bed, I hear sounds coming from the wall that should not be there.","TWN":"關燈後躺在床上，牆裡會傳出我不該聽到的聲音。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"처음에는 의미 없는 잡음처럼 들렸지만, 언제부터인가 이해할 수 있게 됐어요.","JPN":"最初は意味のない雑音のようでしたが、いつからか理解できるようになりました。","ENG":"At first, I dismissed it, but now I seem to understand what it was saying.","TWN":"一開始我以為只是毫無意義的雜訊，但不知道從什麼時候開始，我能聽懂了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그것들은 전부, 현실에 있어선 안 될 무언가를 숭배하는 외설적이고 불경한 주문이란 걸.","JPN":"それらはすべて、現実にいてはならない何かを崇拝する、卑猥で不敬な呪文だということを。","ENG":"They were all obscene and profane chants that worship something that should not exist.","TWN":"那些全都是，崇拜現實中不該有的某種東西的不敬咒語。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"참 이상하죠. 수로에 있던 잔해는 예전에 전부 처리했는데.","JPN":"おかしいですよね。水路にいた残骸は昔に全部片付けたというのに。","ENG":"Strange, is it not? We have long since exterminated the Remains lurking in the waterway.","TWN":"真的很奇怪吧。下水道裡的殘骸，明明之前就已經全都處理了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이번에는 정말로 쥐 떼일지도 모르겠네요.","JPN":"今回は本当にネズミの群れなのかもしれませんね。","ENG":"It might be mere rats this time.","TWN":"說不定這次真的就是老鼠呢。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"기둥을 갉아 먹거나 병을 옮기고 다니는 탓에, 오래된 저택에서는 흔한 골칫거리랍니다.","JPN":"柱をかじったり病気を伝染させるため、古い邸宅ではよくある悩みです。","ENG":"They gnaw at the foundation of this home and spread disease. They are a common nuisance in old mansions such as this.","TWN":"啃食柱子或四處傳染疾病，這是老屋中很常見的麻煩。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};